import { IMessageComposer } from '@nitrots/nitro-renderer';

export class EmsCallDecisionComposer implements IMessageComposer<any[]> {
    private _data: any[];

    constructor(victimUsername: string, accepted: boolean) {
        this._data = [victimUsername, accepted];
        console.log('[📤] EmsCallDecisionComposer sent:', this._data);
    }

    public getMessageArray(): any[] {
        return this._data;
    }
    public dispose(): void {
        /* noop */
    }
}
